"use client";
import { useEnvironmentContext } from "../../providers/environment/use-environment-context.js";
import { isFunction } from "@zag-js/utils";
import { downloadFile } from "@zag-js/file-utils";
//#region src/components/download-trigger/use-download.ts
var useDownload = (props) => {
	const { fileName, mimeType, data } = props;
	const { getWindow } = useEnvironmentContext();
	const saveToDisk = (value) => {
		downloadFile({
			file: value,
			name: fileName,
			type: mimeType,
			win: getWindow()
		});
	};
	const download = () => {
		if (isFunction(data)) {
			const maybePromise = data();
			if (maybePromise instanceof Promise) maybePromise.then(saveToDisk);
			else saveToDisk(maybePromise);
		} else saveToDisk(data);
	};
	return { download };
};
//#endregion
export { useDownload };
